import React from 'react';
import { AbsoluteFill, useCurrentFrame, interpolate } from 'remotion';
import { motion } from 'framer-motion';

interface TerminalComponentProps {
  commands: string[];
  commandDuration: number;
  fontSize?: number;
}

export const TerminalComponent: React.FC<TerminalComponentProps> = ({
  commands,
  commandDuration,
  fontSize = 24,
}) => {
  const frame = useCurrentFrame();

  // Calculate which command should be displayed and how much of it
  const totalCommands = commands.length;
  const framesPerCommand = commandDuration * 60; // 60fps
  const commandIndex = Math.floor(frame / framesPerCommand);
  const progressInCommand = (frame % framesPerCommand) / framesPerCommand;

  // Calculate characters to show
  const currentCommand = commands[Math.min(commandIndex, totalCommands - 1)] || '';
  const charsToShow = Math.floor(progressInCommand * (currentCommand.length + 10));

  const displayText = currentCommand.slice(0, Math.min(charsToShow, currentCommand.length));

  // Syntax highlighting
  const highlightCommand = (text: string) => {
    return text.split(' ').map((part, i) => {
      if (part.startsWith('sudo')) {
        return <span key={i} style={{ color: '#FF6B6B', fontWeight: 'bold' }}>{part} </span>;
      } else if (part.startsWith('-')) {
        return <span key={i} style={{ color: '#4ECDC4' }}>{part} </span>;
      } else if (part.startsWith('http')) {
        return <span key={i} style={{ color: '#95E1D3' }}>{part} </span>;
      }
      return <span key={i}>{part} </span>;
    });
  };

  return (
    <AbsoluteFill style={{ backgroundColor: '#1E1E1E', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{
        fontFamily: 'Monaco, "Courier New", monospace',
        fontSize,
        color: '#F7F7F7',
        padding: 60,
        backgroundColor: '#2D2D2D',
        borderRadius: 10,
        boxShadow: '0 10px 30px rgba(0,0,0,0.5)',
        width: '90%',
        maxWidth: 1200,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: 20 }}>
          <div style={{ width: 12, height: 12, borderRadius: '50%', backgroundColor: '#FF5F56', marginRight: 8 }} />
          <div style={{ width: 12, height: 12, borderRadius: '50%', backgroundColor: '#FFBD2E', marginRight: 8 }} />
          <div style={{ width: 12, height: 12, borderRadius: '50%', backgroundColor: '#27C93F' }} />
          <span style={{ marginLeft: 20, color: '#888', fontSize: 16 }}>Terminal - Ubuntu</span>
        </div>

        <div>
          <span style={{ color: '#4ECDC4' }}>user@ubuntu:~$</span>{' '}
          <span>{highlightCommand(displayText)}</span>
          <motion.span
            animate={{ opacity: [1, 0, 1] }}
            transition={{ duration: 0.8, repeat: Infinity }}
            style={{ display: 'inline-block', width: 12, height: fontSize * 1.2, backgroundColor: '#F7F7F7', verticalAlign: 'middle', marginLeft: 4 }}
          />
        </div>

        {commandIndex > 0 && (
          <div style={{ marginTop: 20, color: '#27C93F' }}>
            ✓ Command executed successfully
          </div>
        )}
      </div>
    </AbsoluteFill>
  );
};

