import React from 'react';
import { useCurrentFrame, interpolate, spring } from 'remotion';
import { motion } from 'framer-motion';

interface ProgressBarProps {
  duration: number;
  label?: string;
  color?: string;
  backgroundColor?: string;
  height?: number;
  showPercentage?: boolean;
}

export const ProgressBar: React.FC<ProgressBarProps> = ({
  duration,
  label = 'Installing...',
  color = '#4ECDC4',
  backgroundColor = '#2D2D2D',
  height = 30,
  showPercentage = true,
}) => {
  const frame = useCurrentFrame();
  const fps = 60;
  const totalFrames = duration * fps;

  const progress = Math.min(frame / totalFrames, 1);
  const percentage = Math.round(progress * 100);

  // Animate the fill
  const fillWidth = interpolate(progress, [0, 1], [0, 100]);

  return (
    <div style={{
      position: 'absolute',
      left: '50%',
      top: '50%',
      transform: 'translate(-50%, -50%)',
      width: '80%',
      maxWidth: 800,
    }}>
      {label && (
        <div style={{
          marginBottom: 16,
          fontSize: 24,
          color: '#F7F7F7',
          fontFamily: 'Arial, sans-serif',
          textAlign: 'center',
        }}>
          {label}
        </div>
      )}

      <div style={{
        width: '100%',
        height,
        backgroundColor,
        borderRadius: height / 2,
        overflow: 'hidden',
        position: 'relative',
      }}>
        <motion.div
          initial={{ width: 0 }}
          animate={{ width: `${fillWidth}%` }}
          transition={{ duration: 0.5, ease: 'easeOut' }}
          style={{
            height: '100%',
            backgroundColor: color,
            position: 'relative',
          }}
        >
          {/* Shimmer effect */}
          <motion.div
            initial={{ x: '-100%' }}
            animate={{ x: '200%' }}
            transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '50%',
              height: '100%',
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.3), transparent)',
            }}
          />
        </motion.div>
      </div>

      {showPercentage && (
        <motion.div
          key={percentage}
          initial={{ scale: 1.2, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          style={{
            marginTop: 16,
            fontSize: 32,
            color: color,
            fontFamily: 'Arial, sans-serif',
            textAlign: 'center',
            fontWeight: 'bold',
          }}
        >
          {percentage}%
        </motion.div>
      )}

      {/* Status messages */}
      {progress < 0.3 && (
        <div style={{ marginTop: 12, fontSize: 18, color: '#888', textAlign: 'center' }}>
          Downloading package...
        </div>
      )}
      {progress >= 0.3 && progress < 0.7 && (
        <div style={{ marginTop: 12, fontSize: 18, color: '#888', textAlign: 'center' }}>
          Extracting files...
        </div>
      )}
      {progress >= 0.7 && progress < 1 && (
        <div style={{ marginTop: 12, fontSize: 18, color: '#888', textAlign: 'center' }}>
          Configuring Arduino...
        </div>
      )}
      {progress >= 1 && (
        <div style={{ marginTop: 12, fontSize: 18, color: '#27C93F', textAlign: 'center', fontWeight: 'bold' }}>
          ✓ Installation Complete!
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { AbsoluteFill, useCurrentFrame, interpolate } from 'remotion';
import { motion } from 'framer-motion';
import { CheckCircle2, XCircle, AlertTriangle } from 'lucide-react';

type StatusType = 'success' | 'error' | 'warning';

interface StatusComponentProps {
  type: StatusType;
  message: string;
  duration?: number;
}

export const StatusComponent: React.FC<StatusComponentProps> = ({
  type,
  message,
  duration = 3,
}) => {
  const frame = useCurrentFrame();
  const fps = 60;
  const totalFrames = duration * fps;

  const progress = frame / totalFrames;
  const opacity = interpolate(progress, [0, 0.1, 0.9, 1], [0, 1, 1, 0]);
  const scale = interpolate(progress, [0, 0.1], [0.8, 1]);

  const config = {
    success: { color: '#27C93F', icon: CheckCircle2 },
    error: { color: '#FF6B6B', icon: XCircle },
    warning: { color: '#FFBD2E', icon: AlertTriangle },
  };

  const { color, icon: Icon } = config[type];

  return (
    <AbsoluteFill style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
    }}>
      <motion.div
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        transition={{ duration: 0.3 }}
        style={{
          backgroundColor: '#2D2D2D',
          padding: '60px 80px',
          borderRadius: 16,
          textAlign: 'center',
          opacity,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 60px rgba(0,0,0,0.6)',
        }}
      >
        <motion.div
          initial={{ rotate: -180, scale: 0 }}
          animate={{ rotate: 0, scale: 1 }}
          transition={{ duration: 0.5, type: 'spring', bounce: 0.5 }}
          style={{ marginBottom: 24 }}
        >
          <Icon size={80} color={color} strokeWidth={2} />
        </motion.div>

        <motion.div
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.3, delay: 0.2 }}
          style={{
            fontSize: 32,
            color: color,
            fontWeight: 'bold',
            marginBottom: 16,
            fontFamily: 'Arial, sans-serif',
          }}
        >
          {type === 'success' && '成功'}
          {type === 'error' && '错误'}
          {type === 'warning' && '注意'}
        </motion.div>

        <motion.div
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.3, delay: 0.3 }}
          style={{
            fontSize: 24,
            color: '#F7F7F7',
            fontFamily: 'Arial, sans-serif',
          }}
        >
          {message}
        </motion.div>

        {type === 'warning' && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.3, delay: 0.5 }}
            style={{
              marginTop: 24,
              fontSize: 18,
              color: '#888',
              fontFamily: 'Arial, sans-serif',
            }}
          >
            按任意键继续...
          </motion.div>
        )}
      </motion.div>
    </AbsoluteFill>
  );
};

import React from 'react';
import { useCurrentFrame, interpolate } from 'remotion';
import { motion } from 'framer-motion';
import { Check, ChevronRight } from 'lucide-react';

interface Step {
  id: string;
  label: string;
  completed: boolean;
  current: boolean;
}

interface StepIndicatorProps {
  steps: Step[];
  duration?: number;
}

export const StepIndicator: React.FC<StepIndicatorProps> = ({
  steps,
  duration = 5,
}) => {
  const frame = useCurrentFrame();
  const fps = 60;
  const totalFrames = duration * fps;

  return (
    <div style={{
      position: 'absolute',
      left: '50%',
      top: 100,
      transform: 'translateX(-50%)',
      width: '90%',
      maxWidth: 1200,
    }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 16,
      }}>
        {steps.map((step, index) => (
          <React.Fragment key={step.id}>
            {/* Step node */}
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.3, delay: index * 0.1 }}
              style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 12,
              }}
            >
              {/* Circle */}
              <div
                style={{
                  width: 80,
                  height: 80,
                  borderRadius: '50%',
                  backgroundColor: step.completed ? '#27C93F' : step.current ? '#4ECDC4' : '#2D2D2D',
                  border: step.current ? '3px solid #4ECDC4' : '3px solid #444',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  boxShadow: step.current ? '0 0 20px rgba(78, 205, 196, 0.5)' : 'none',
                }}
              >
                {step.completed ? (
                  <motion.div
                    initial={{ scale: 0, rotate: -180 }}
                    animate={{ scale: 1, rotate: 0 }}
                    transition={{ duration: 0.5, delay: 0.1 }}
                  >
                    <Check size={40} color="#1E1E1E" strokeWidth={3} />
                  </motion.div>
                ) : step.current ? (
                  <motion.div
                    initial={{ scale: 0.5, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ duration: 0.3 }}
                  >
                    <span style={{
                      fontSize: 36,
                      color: '#1E1E1E',
                      fontWeight: 'bold',
                      fontFamily: 'Arial, sans-serif',
                    }}>
                      {index + 1}
                    </span>
                  </motion.div>
                ) : (
                  <span style={{
                    fontSize: 32,
                    color: '#888',
                    fontFamily: 'Arial, sans-serif',
                  }}>
                    {index + 1}
                  </span>
                )}
              </div>

              {/* Label */}
              <motion.div
                initial={{ y: 10, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.3, delay: index * 0.1 + 0.1 }}
                style={{
                  fontSize: 18,
                  color: step.current || step.completed ? '#F7F7F7' : '#888',
                  fontWeight: step.current ? 'bold' : 'normal',
                  fontFamily: 'Arial, sans-serif',
                  textAlign: 'center',
                  whiteSpace: 'nowrap',
                }}
              >
                {step.label}
              </motion.div>
            </motion.div>

            {/* Arrow */}
            {index < steps.length - 1 && (
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ duration: 0.3, delay: index * 0.1 + 0.2 }}
                style={{
                  width: 60,
                  display: 'flex',
                  justifyContent: 'center',
                }}
              >
                <ChevronRight
                  size={40}
                  color={steps[index].completed ? '#4ECDC4' : '#444'}
                  strokeWidth={2}
                />
              </motion.div>
            )}
          </React.Fragment>
        ))}
      </div>

      {/* Animated line connecting steps */}
      <svg
        style={{
          position: 'absolute',
          top: 140,
          left: 0,
          width: '100%',
          height: 4,
        }}
      >
        <defs>
          <linearGradient id="progressGradient" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#4ECDC4" />
            <stop offset="100%" stopColor="#95E1D3" />
          </linearGradient>
        </defs>
        {steps.slice(0, -1).map((_, index) => {
          const isCompleted = steps[index].completed;
          return (
            <line
              key={index}
              x1={`${(index * 25) + 12.5}%`}
              y1="50%"
              x2={`${(index * 25) + 25}%`}
              y2="50%"
              stroke={isCompleted ? 'url(#progressGradient)' : '#444'}
              strokeWidth="4"
              strokeLinecap="round"
            />
          );
        })}
      </svg>
    </div>
  );
};

